const queryParams = $input.first().json.query || {};
const mois = queryParams.mois || (() => {
  const date = new Date();
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
})();

const prev_month = new Date(mois + '-01');
prev_month.setMonth(prev_month.getMonth() - 1);
const prev_mois = `${prev_month.getFullYear()}-${String(prev_month.getMonth() + 1).padStart(2, '0')}`;

return {
  json: {
    mois,
    prev_mois
  }
};

const allResults = $input.all();

const revenueByType = {};
if (allResults[2] && allResults[2].json) {
  allResults[2].json.forEach(row => {
    revenueByType[row.type] = row.total;
  });
}

const mrr = allResults[3] && allResults[3].json[0] ? allResults[3].json[0].mrr : 0;
const commissionsDues = allResults[4] && allResults[4].json[0] ? allResults[4].json[0].commissions_dues : 0;
const commissionsPaid = allResults[5] && allResults[5].json[0] ? allResults[5].json[0].commissions_payees : 0;
const prevTotal = allResults[6] && allResults[6].json[0] ? allResults[6].json[0].prev_total : 0;

const totalBrut = Object.values(revenueByType).reduce((a, b) => a + b, 0);
const evolution = prevTotal > 0 ? ((totalBrut - prevTotal) / prevTotal * 100).toFixed(2) : 0;
const netRevenue = totalBrut - (commissionsDues + commissionsPaid);

return {
  json: {
    mois: allResults[1].json.mois,
    mrr,
    revenue_par_type: revenueByType,
    total_brut: totalBrut,
    commissions_dues: commissionsDues,
    commissions_payees: commissionsPaid,
    net_revenue: netRevenue,
    evolution: parseFloat(evolution)
  }
};
